const fs   = require('fs');
const path = require('path');

const CONFIG_DIR = '/config';

const CONFIG_MAP = {
    device_registry: 'device_registry.json',
    flow_registry:   'flow_registry.json',
    notifications:   'notifications.json',
    thresholds:      'thresholds.json',
    healthchecks:    'healthchecks.json',
    secrets:         'secrets.json'
};

// Determine scope: selective or full
const prefix = 'highland/command/config/reload/';
const topic  = msg.topic || '';
let scope = null;

if (topic.startsWith(prefix)) {
    const name = topic.slice(prefix.length);
    if (!CONFIG_MAP[name]) {
        node.warn(`[Config Loader] Unknown config name: ${name}`);
        return null;
    }
    scope = name;
}

const toLoad = scope
    ? { [scope]: CONFIG_MAP[scope] }
    : CONFIG_MAP;

// Load or initialize global config object
let config = global.get('config') || {};

const loaded = [];
const errors = [];

for (const [key, filename] of Object.entries(toLoad)) {
    const filepath = path.join(CONFIG_DIR, filename);
    try {
        const raw   = fs.readFileSync(filepath, 'utf8');
        config[key] = JSON.parse(raw);
        loaded.push(key);
    } catch (err) {
        errors.push({ key, filename, error: err.message });
        node.warn(`[Config Loader] Failed to load ${filename}: ${err.message}`);
    }
}

global.set('config', config);

msg.topic   = 'highland/status/config/loaded';
msg.payload = {
    loaded,
    errors,
    scope:     scope || 'all',
    timestamp: new Date().toISOString()
};

return msg;
